contracts/GameRoom.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import "./StakingVault.sol";

contract GameRoom {
    enum GameState { PENDING, PLAYING, ENDED }

    struct GameConfig {
        uint256 minPlayers;
        uint256 maxPlayers;
        uint256 minStake;
        uint256 maxStake;
        uint256 jokerCount;
        uint256[10] cardCounts;
    }

    struct Player {
        address addr;
        uint256 stakeAmount;
        bool isActive;
        bool isOut;
        uint256[10] handCards;
        uint256 jokerCount;
    }

    uint256 public immutable gameId;
    StakingVault public immutable stakingVault;
    GameConfig public config;
    GameState public gameState;
    address public immutable host;

    address[] public players;
    mapping(address => Player) public playerData;
    uint256 public currentPlayerIndex;

    event PlayerJoined(uint256 indexed gameId, address indexed player, uint256 stakeAmount);
    event GameStarted(uint256 indexed gameId);
    event CardTaken(address indexed from, address indexed to, uint8 cardNumber);
    event PlayerOut(address indexed player);
    event GameEnded(uint256 indexed gameId, address[] losers, address[] winners);

    constructor(
        uint256 _gameId,
        address payable  _stakingVault,
        GameConfig memory _config
    ) {
        require(_stakingVault != address(0), "!vault");
        gameId = _gameId;
        stakingVault = StakingVault(_stakingVault);
        config = _config;
        gameState = GameState.PENDING;
        host = msg.sender;
    }

    function joinGame() external payable {
        require(gameState == GameState.PENDING, "!pending");
        require(!playerData[msg.sender].isActive, "joined");
        require(players.length < config.maxPlayers, "full");

        uint256 val = msg.value;
        if (config.maxStake == 0) {
            require(val == config.minStake, "fixed stake");
        } else {
            require(val >= config.minStake && val <= config.maxStake, "range");
        }

        Player storage p = playerData[msg.sender];
        p.addr = msg.sender;
        p.stakeAmount = val;
        p.isActive = true;
        players.push(msg.sender);

        emit PlayerJoined(gameId, msg.sender, val);

        if (players.length == config.maxPlayers) {
            _startGame();
        }
    }

    function _startGame() internal {
        require(players.length >= config.minPlayers, "!enough");
        gameState = GameState.PLAYING;
        _shuffleAndDealAllCards();
        emit GameStarted(gameId);
    }

    function _shuffleAndDealAllCards() internal {
        uint256 pCount = players.length;
        uint256[] memory deck = _generateFullDeck();

        for (uint i = 0; i < deck.length; i++) {
            address to = players[i % pCount];
            uint8 num = uint8(deck[i]);
            playerData[to].handCards[num]++;
            _autoEliminate(to, num);
        }

        uint256 jokerTotal = config.jokerCount;
        for (uint i = 0; i < jokerTotal; i++) {
            address to = players[uint(keccak256(abi.encodePacked(block.timestamp, i))) % pCount];
            playerData[to].jokerCount += 1;
        }
    }

    function _generateFullDeck() internal view returns (uint256[] memory) {
        uint256 totalCards;
        for (uint i = 0; i < 10; i++) totalCards += config.cardCounts[i];

        uint256[] memory deck = new uint256[](totalCards);
        uint idx;
        for (uint8 num = 0; num < 10; num++) {
            uint cnt = config.cardCounts[num];
            for (uint i = 0; i < cnt; i++) deck[idx++] = num;
        }

        for (uint i = 0; i < deck.length; i++) {
            uint r = uint(keccak256(abi.encodePacked(block.timestamp, i))) % deck.length;
            (deck[i], deck[r]) = (deck[r], deck[i]);
        }
        return deck;
    }

    /// @param cardNumber 0 = 小丑，1–10 = 数字牌（与手牌下标 0–9 对应）
    function takeCard(address target, uint8 cardNumber) external {
        require(gameState == GameState.PLAYING, "!playing");
        require(players[currentPlayerIndex] == msg.sender, "!turn");
        require(!playerData[msg.sender].isOut, "out");
        require(target != address(0), "!target");

        if (cardNumber == 0) {
            require(playerData[target].jokerCount > 0, "no joker");
            playerData[target].jokerCount--;
            playerData[msg.sender].jokerCount++;
            emit CardTaken(target, msg.sender, 0);
        } else {
            require(cardNumber >= 1 && cardNumber <= 10, "card 1-10");
            uint8 idx = cardNumber - 1;
            require(playerData[target].handCards[idx] > 0, "no card");

            playerData[target].handCards[idx]--;
            playerData[msg.sender].handCards[idx]++;
            _autoEliminate(msg.sender, idx);
            emit CardTaken(target, msg.sender, cardNumber);
        }

        if (_isAllClear(msg.sender)) {
            playerData[msg.sender].isOut = true;
            emit PlayerOut(msg.sender);
        }

        _nextTurn();
        if (_isGameOver()) _endGame();
    }

    function _autoEliminate(address player, uint8 idx) internal {
        uint cnt = playerData[player].handCards[idx];
        if (cnt >= 2) playerData[player].handCards[idx] = cnt % 2;
    }

    function _isAllClear(address player) internal view returns (bool) {
        if (playerData[player].jokerCount > 0) return false;
        for (uint8 i = 0; i < 10; i++) {
            if (playerData[player].handCards[i] > 0) return false;
        }
        return true;
    }

    function _nextTurn() internal {
        uint nextIdx = (currentPlayerIndex + 1) % players.length;
        while (playerData[players[nextIdx]].isOut) {
            nextIdx = (nextIdx + 1) % players.length;
        }
        currentPlayerIndex = nextIdx;
    }

    function _isGameOver() internal view returns (bool) {
        uint active;
        for (uint i = 0; i < players.length; i++) {
            if (!playerData[players[i]].isOut) active++;
        }
        return active <= 1;
    }

    function _endGame() internal {
        gameState = GameState.ENDED;

        address[] memory losers = new address[](players.length);
        address[] memory winners = new address[](players.length);
        uint l;
        uint w;

        for (uint i = 0; i < players.length; i++) {
            address p = players[i];
            if (playerData[p].jokerCount > 0) losers[l++] = p;
            else winners[w++] = p;
        }

        assembly {
            mstore(losers, l)
            mstore(winners, w)
        }

        (bool sent, ) = address(stakingVault).call{value: address(this).balance}("");
        require(sent, "!transfer");

        stakingVault.distributeRewards(gameId, winners, losers);
        emit GameEnded(gameId, losers, winners);
    }

    function getPlayerCards(address p) external view returns (uint256[10] memory, uint256) {
        return (playerData[p].handCards, playerData[p].jokerCount);
    }
}

contracts/StakingVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

/**
 * @title StakingVault
 * @dev 处理BrokerChain原生BKC质押、锁定和收益分配
 * 无需ERC20授权，直接接收原生BKC
 */
contract StakingVault {
    // 游戏质押记录：gameId → player → stakeAmount
    mapping(uint256 => mapping(address => uint256)) public gameStakes;
    // 游戏奖池：gameId → totalPool
    mapping(uint256 => uint256) public gamePools;
    // 游戏房间：gameId -> roomAddress
    mapping(uint256 => address) public gameRooms;
    // 协议手续费率：1%（10/1000）
    uint256 public constant FEE_RATE = 10;
    // 手续费接收地址（部署者）
    address public immutable feeReceiver;
    address public factory;

    // 事件定义
    event Staked(uint256 indexed gameId, address indexed player, uint256 amount);
    event RewardsDistributed(uint256 indexed gameId, uint256 totalRewards, uint256 fee);
    event GameRoomRegistered(uint256 indexed gameId, address indexed room);

    /**
     * @dev 构造函数：初始化手续费接收地址
     */
    constructor() {
        feeReceiver = msg.sender;
        factory = msg.sender;
    }

    function setFactory(address _factory) external {
        require(msg.sender == feeReceiver, "StakingVault: only fee receiver");
        require(_factory != address(0), "StakingVault: factory is zero");
        factory = _factory;
    }

    /**
     * @dev 接收原生BKC的回调函数（必须实现，否则合约无法接收BKC）
     */
    receive() external payable {}

    /**
     * @dev 玩家质押原生BKC到指定游戏
     * @param gameId 游戏ID
     * 注意：质押金额通过交易的value参数传入，而非函数参数
     */
    function stake(uint256 gameId) external payable {
        uint256 amount = msg.value; // 从交易value中获取质押金额（原生BKC，wei单位）
        require(amount > 0, "StakingVault: amount must be > 0");
        require(gamePools[gameId] + amount > gamePools[gameId], "StakingVault: overflow");

        // 更新质押记录和奖池（无需转账，BKC已通过msg.value进入合约）
        gameStakes[gameId][msg.sender] += amount;
        gamePools[gameId] += amount;

        emit Staked(gameId, msg.sender, amount);
    }

    /**
     * @dev 由房间代玩家质押（用于GameRoom.joinGame时透传玩家地址）
     */
    function stakeFor(uint256 gameId, address player) external payable {
        uint256 amount = msg.value;
        require(player != address(0), "StakingVault: player is zero");
        require(amount > 0, "StakingVault: amount must be > 0");
        require(gamePools[gameId] + amount > gamePools[gameId], "StakingVault: overflow");

        gameStakes[gameId][player] += amount;
        gamePools[gameId] += amount;

        emit Staked(gameId, player, amount);
    }

    function registerGameRoom(uint256 gameId, address room) external {
        require(msg.sender == factory, "StakingVault: only factory");
        require(room != address(0), "StakingVault: room is zero");
        require(gameRooms[gameId] == address(0), "StakingVault: room exists");
        gameRooms[gameId] = room;
        emit GameRoomRegistered(gameId, room);
    }

    /**
     * @dev 分配游戏奖励（仅游戏房间合约可调用）
     * @param gameId 游戏ID
     * @param winners 获胜者列表
     * @param losers 失败者列表
     */
    function distributeRewards(
        uint256 gameId,
        address[] calldata winners,
        address[] calldata losers
    ) external {
        require(msg.sender == gameRooms[gameId], "StakingVault: only game room");
        uint256 totalPool = gamePools[gameId];
        require(totalPool > 0, "StakingVault: no pool for game");
        require(winners.length > 0, "StakingVault: no winners");

        // 计算手续费和可分配奖励
        uint256 fee = (totalPool * FEE_RATE) / 1000;
        uint256 rewardPool = totalPool - fee;

        // 发放手续费（原生BKC转账）
        if (fee > 0) {
            (bool feeSuccess, ) = feeReceiver.call{value: fee}("");
            require(feeSuccess, "StakingVault: fee transfer failed");
        }

        // 仅在获胜者内部按质押比例分配奖励
        uint256 winnersStakeTotal = 0;
        for (uint256 i = 0; i < winners.length; i++) {
            winnersStakeTotal += gameStakes[gameId][winners[i]];
        }
        require(winnersStakeTotal > 0, "StakingVault: winners stake is zero");

        for (uint256 i = 0; i < winners.length; i++) {
            address winner = winners[i];
            uint256 winnerStake = gameStakes[gameId][winner];
            if (winnerStake == 0) continue;

            uint256 reward = (winnerStake * rewardPool) / winnersStakeTotal;
            if (reward > 0) {
                (bool rewardSuccess, ) = winner.call{value: reward}("");
                require(rewardSuccess, "StakingVault: reward transfer failed");
            }

            // 清空获胜者质押记录
            delete gameStakes[gameId][winner];
        }

        // 清空失败者质押记录
        for (uint256 i = 0; i < losers.length; i++) {
            delete gameStakes[gameId][losers[i]];
        }

        // 清空奖池
        delete gamePools[gameId];

        emit RewardsDistributed(gameId, rewardPool, fee);
    }

    /**
     * @dev 查询玩家在指定游戏的质押额
     * @param gameId 游戏ID
     * @param player 玩家地址
     * @return 质押金额
     */
    function getPlayerStake(uint256 gameId, address player) external view returns (uint256) {
        return gameStakes[gameId][player];
    }

    /**
     * @dev 紧急提取合约中多余的BKC（仅部署者可用）
     */
    function emergencyWithdraw(uint256 amount) external {
        require(msg.sender == feeReceiver, "StakingVault: only fee receiver");
        require(address(this).balance >= amount, "StakingVault: insufficient balance");
        (bool success, ) = feeReceiver.call{value: amount}("");
        require(success, "StakingVault: emergency transfer failed");
    }
}

